/* ─── Fonts & Global Reset ───────────────────────────────────────────────── */
const GlobalStyles = () => (
  <style>{`
    @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400;1,500&family=Jost:wght@200;300;400;500&display=swap');
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    html { scroll-behavior: smooth; font-size: 16px; }
    body { background: #060606; color: #f7f7f5; overflow-x: hidden; font-family: 'Jost', sans-serif; }
    ::selection { background: #C9A96E; color: #060606; }
    .font-serif { font-family: 'Cormorant Garamond', serif; }
    .reveal { opacity: 0; transform: translateY(28px); transition: opacity 0.95s ease, transform 0.95s ease; }
    .reveal.visible { opacity: 1; transform: translateY(0); }
    .d1 { transition-delay: 0.15s; }
    .d2 { transition-delay: 0.30s; }
    .d3 { transition-delay: 0.45s; }
  `}</style>
)

/* ─── Scroll Reveal ──────────────────────────────────────────────────────── */
function useScrollReveal() {
  useEffect(() => {
    const obs = new IntersectionObserver(
      entries => entries.forEach(e => { if (e.isIntersecting) e.target.classList.add("visible") }),
      { threshold: 0.1, rootMargin: "0px 0px -40px 0px" }
    )
    document.querySelectorAll(".reveal").forEach(el => obs.observe(el))
    return () => obs.disconnect()
  }, [])
}

/* ─── NavBar ─────────────────────────────────────────────────────────────── */
function NavBar() {
  const [scrolled, setScrolled] = useState(false)
  const [open, setOpen] = useState(false)

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 50)
    window.addEventListener("scroll", fn)
    return () => window.removeEventListener("scroll", fn)
  }, [])

  const go = (id: string) => {
    setOpen(false)
    document.getElementById(id)?.scrollIntoView({ behavior: "smooth" })
  }

  return (
    <>
      <style>{`
        .nav {
          position:fixed;top:0;left:0;right:0;z-index:200;
          transition: all .5s ease;
        }
        .nav.solid {
          background:rgba(4,4,4,.97);
          backdrop-filter:blur(16px);
          border-bottom:1px solid rgba(255,255,255,.05);
          box-shadow:0 1px 40px rgba(0,0,0,.5);
        }
        .nav-inner {
          max-width:1400px;margin:0 auto;
          padding:0 48px;height:76px;
          display:flex;align-items:center;justify-content:space-between;
        }
        .nav-logo img {height:25px;filter:invert(1);cursor:pointer;opacity:.9;transition:opacity .2s}
        .nav-logo img:hover {opacity:1}
        .nav-links { display:flex;align-items:center;gap:40px }
        .nav-link {
          font-size:9.5px;letter-spacing:.24em;text-transform:uppercase;
          color:rgba(255,255,255,.45);cursor:pointer;
          background:none;border:none;padding:0;transition:color .25s;
        }
        .nav-link:hover {color:#fff}
        .nav-cta {
          font-size:9.5px;letter-spacing:.24em;text-transform:uppercase;
          color:#060606;background:#f7f7f5;border:none;
          padding:11px 24px;cursor:pointer;transition:background .3s,color .3s;
        }
        .nav-cta:hover {background:#C9A96E;color:#060606}
        .burger {
          display:none;flex-direction:column;gap:5px;
          background:none;border:none;cursor:pointer;padding:6px;
        }
        .burger span {
          display:block;width:22px;height:1px;
          background:rgba(255,255,255,.7);transition:all .3s;
        }
        .mob-menu {
          display:none;position:fixed;top:76px;left:0;right:0;
          background:rgba(4,4,4,.99);padding:28px 48px 36px;
          border-bottom:1px solid rgba(255,255,255,.06);
          flex-direction:column;gap:24px;
        }
        .mob-menu.open {display:flex}
        @media(max-width:768px){
          .nav-links{display:none}
          .burger{display:flex}
          .nav-inner{padding:0 24px}
        }
      `}</style>

      <nav className={`nav ${scrolled ? "solid" : ""}`}>
        <div className="nav-inner">
          <div className="nav-logo">
            <img src={LOGO_SRC} alt="HAMON" onClick={() => window.scrollTo({top:0,behavior:"smooth"})} />
          </div>
          <div className="nav-links">
            <button className="nav-link" onClick={()=>go("benefits")}>Collection</button>
            <button className="nav-link" onClick={()=>go("lifestyle")}>The Brand</button>
            <button className="nav-link" onClick={()=>go("product")}>Design</button>
            <button className="nav-cta"  onClick={()=>go("waitlist")}>Early Access</button>
          </div>
          <button className="burger" onClick={()=>setOpen(o=>!o)}>
            <span style={{transform:open?"rotate(45deg) translate(4px,4px)":"none"}}/>
            <span style={{opacity:open?0:1}}/>
            <span style={{transform:open?"rotate(-45deg) translate(4px,-4px)":"none"}}/>
          </button>
        </div>
      </nav>
      <div className={`mob-menu ${open?"open":""}`}>
        {["benefits","lifestyle","product","waitlist"].map(id=>(
          <button key={id} className="nav-link"
            style={{color:"rgba(255,255,255,.65)",fontSize:"11px",textAlign:"left"}}
            onClick={()=>go(id)}>
            {id.charAt(0).toUpperCase()+id.slice(1)}
          </button>
        ))}
      </div>
    </>
  )
}

